// // This register does not capture the input data 'd' on a rising edge of the clock when the 'enable' input is high.
module top_module(
    input wire clk,
    input wire reset,
    input wire enable,
    input wire [7:0] d,
    output reg [7:0] q
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            q <= 8'b00000000;
        end else if (enable) begin
            q <= d;
        end
    end

endmodule
